package com.example.usage;

import com.seed.api.SeedApiClient;
import com.seed.api.requests.GetPlantRequest;

public class Example {
    public static void main(String[] args) {
        SeedApiClient client = SeedApiClient
            .builder()
            .build();

        client.getPlant(
            "plantId",
            GetPlantRequest
                .builder()
                .build()
        );
    }
}

